package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void testGenerateNonExecutableJson_setsFlagToTrue_andReturnsSameInstance() throws Exception {
    // Initially the private field generateNonExecutableJson should be false (default)
    Field field = GsonBuilder.class.getDeclaredField("generateNonExecutableJson");
    field.setAccessible(true);
    boolean initialValue = field.getBoolean(gsonBuilder);
    assertFalse(initialValue, "Initial generateNonExecutableJson should be false");

    // Call the focal method
    GsonBuilder returned = gsonBuilder.generateNonExecutableJson();

    // Assert the method returns the same instance (this)
    assertSame(gsonBuilder, returned, "generateNonExecutableJson should return the same GsonBuilder instance");

    // Assert the private field is now true
    boolean updatedValue = field.getBoolean(gsonBuilder);
    assertTrue(updatedValue, "generateNonExecutableJson should be set to true after calling the method");
  }
}
